// n8n Code Node v2 — format laporan harian untuk Telegram

function fmt(n) {
  const num = Number(n) || 0;
  return 'Rp ' + num.toLocaleString('id-ID');
}

// Ambil item pertama dari input
const items = $input.all();
const raw = items[0]?.json || {};

// Jika API error atau response kosong
if (!raw || Object.keys(raw).length === 0) {
  return [{ json: { message: '⚠️ API returned empty response' } }];
}

if (raw.success === false) {
  return [{ json: { message: '⚠️ API Error: ' + (raw.error || 'Unknown') } }];
}

// Extract data — handle both {success,data} wrapper and direct data
const d = raw.data || raw;
const s = d.summary || {};
const c = d.comparison || {};
const platforms = Array.isArray(d.platforms) ? d.platforms : [];
const aging = d.aging || { total: 0, detail: {} };
const debug = d._debug || {};

// Platform lines
let platformLines = '├ Tidak ada data platform';
if (platforms.length > 0) {
  platformLines = platforms.map(function(p) {
    return '├ ' + (p.platform || 'Unknown') + ' : ' + fmt(p.omzet) + ' (' + (p.count || 0) + ' order)';
  }).join('\n');
}

// Aging backlog
const agingDetail = aging.detail || {};
let agingStr = '├ Tidak ada';
const agingKeys = Object.keys(agingDetail);
if (agingKeys.length > 0) {
  agingStr = agingKeys.map(function(k) {
    return '├ ' + k + ': ' + agingDetail[k];
  }).join('\n');
}

// Tanggal
const dateStr = d.date || new Date().toISOString().slice(0, 10);
let tgl = dateStr;
try {
  tgl = new Date(dateStr + 'T00:00:00+07:00').toLocaleDateString('id-ID', {
    weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
  });
} catch(e) { /* fallback to dateStr */ }

const omzet = Number(s.omzet) || 0;
const hpp = Number(s.hpp) || 0;
const gp = Number(s.grossProfit) || 0;
const margin = omzet > 0 ? ((gp / omzet) * 100).toFixed(1) : '0';

// Comparison
const prevOmzet = Number(c.prevOmzet) || 0;
const omzetDiff = Number(c.omzetDiff) || 0;
const omzetDiffPct = c.omzetDiffPct;
const orderCountDiff = Number(c.orderCountDiff) || 0;

let omzetCompare = '—';
if (prevOmzet > 0) {
  const arrow = omzetDiff >= 0 ? '↑' : '↓';
  const pctPart = omzetDiffPct ? ' (' + (omzetDiff >= 0 ? '+' : '') + omzetDiffPct + '%)' : '';
  omzetCompare = arrow + ' ' + fmt(Math.abs(omzetDiff)) + pctPart;
}
const orderArrow = orderCountDiff >= 0 ? '↑' : '↓';
const orderCompare = orderArrow + ' ' + Math.abs(orderCountDiff) + ' order';

// Build message
const lines = [];
lines.push('📊 LAPORAN HARIAN ELYASR');
lines.push(tgl + ' — 17.30 WIB');
lines.push('');
lines.push('💰 OMZET & PROFIT (Hari Ini)');
lines.push('├ Real Omzet    : ' + fmt(s.omzet));
lines.push('├ HPP Total     : ' + fmt(s.hpp));
lines.push('└ Gross Profit  : ' + fmt(s.grossProfit) + ' (' + margin + '%)');
lines.push('');
lines.push('📦 ORDER');
lines.push('├ Total Masuk  : ' + (s.totalOrder || 0) + ' order');
lines.push('├ Terkirim     : ' + (s.terkirim || 0) + ' order');
lines.push('├ Pending Kirim: ' + (s.perluKirim || 0) + ' order');
lines.push('└ Dibatalkan   : ' + (s.batal || 0) + ' order');
lines.push('');
lines.push('🏪 PER PLATFORM');
lines.push(platformLines);
lines.push('');
lines.push('😡 AGING BACKLOG (' + (aging.total || 0) + ' order pending)');
lines.push(agingStr);
lines.push('');
lines.push('🔥 STOK KRITIS: ' + (d.stokKritis || 0) + ' SKU perlu restock');
lines.push('');
lines.push('📈 VS KEMARIN');
lines.push('├ Omzet  : ' + omzetCompare);
lines.push('└ Order  : ' + orderCompare);
lines.push('');
// Debug info (hapus setelah fix)
if (d._error) {
  lines.push('⚠️ SQL ERROR: ' + d._error);
  lines.push('');
}
if (debug.gteStr || debug.dateFrom) {
  lines.push('🔧 DEBUG:');
  lines.push('├ dateFrom: ' + (debug.dateFrom || debug.gteStr));
  lines.push('├ gte: ' + (debug.gteDate || debug.lteStr));
  lines.push('├ lte: ' + (debug.lteDate || ''));
  lines.push('├ rows: ' + (debug.todayOrdersRows || debug.todayOrdersRaw || 0));
  lines.push('└ platforms: ' + (debug.platformRows || debug.platformsRaw || 0));
  lines.push('');
}
lines.push('This message was sent automatically with n8n');

const message = lines.join('\n');

return [{ json: { message: message } }];
